// packages/database/src/db/schema/dataset.ts
// Drizzle table: dataset (generated by scripts/split-schema.ts)

import {
  pgTable,
  uniqueIndex,
  index,
  text,
  bigint,
  boolean,
  timestamp,
  integer,
  jsonb,
  type AnyPgColumn,
  datasetStatus,
  vectorDbType,
} from './_shared'
import { createId } from '@paralleldrive/cuid2'

import { User } from './user'
import { Organization } from './organization'
import type { ChunkSettings } from '../../types/chunk-settings'

/** Default chunk settings for datasets */
const DEFAULT_CHUNK_SETTINGS: ChunkSettings = {
  strategy: 'FIXED_SIZE',
  size: 1024,
  overlap: 50,
  delimiter: '\n\n',
  preprocessing: {
    normalizeWhitespace: true,
    removeUrlsAndEmails: false,
  },
}

/** Drizzle table for dataset */
export const Dataset = pgTable(
  'Dataset',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    name: text().notNull(),
    description: text(),
    status: datasetStatus().default('ACTIVE').notNull(),
    isPublic: boolean().default(false).notNull(),
    documentCount: integer().default(0).notNull(),
    // You can use { mode: "bigint" } if numbers are exceeding js number limitations
    totalSize: bigint({ mode: 'number' }).default(0).notNull(),
    lastIndexedAt: timestamp({ precision: 3 }),
    /** Consolidated chunking settings as JSONB */
    chunkSettings: jsonb().$type<ChunkSettings>().default(DEFAULT_CHUNK_SETTINGS).notNull(),
    vectorDbConfig: jsonb(),
    /** Embedding model in "provider:model" format (e.g., "openai:text-embedding-3-large") */
    embeddingModel: text(),
    vectorDimension: integer(),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    createdById: text()
      .notNull()
      .references((): AnyPgColumn => User.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    vectorDbType: vectorDbType().default('POSTGRESQL').notNull(),
    searchConfig: jsonb().default({ searchType: 'hybrid' }).notNull(),
  },
  (table) => [
    index('Dataset_createdById_idx').using('btree', table.createdById.asc().nullsLast()),
    index('Dataset_organizationId_idx').using('btree', table.organizationId.asc().nullsLast()),
    uniqueIndex('Dataset_organizationId_name_key').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.name.asc().nullsLast()
    ),
    index('Dataset_status_idx').using('btree', table.status.asc().nullsLast()),

    // Composite index for organization + status lookups (optimizes search queries)
    index('idx_dataset_org_status').using(
      'btree',
      table.organizationId.asc(),
      table.status.asc()
    ),
  ]
)
